const data = $input.first().json;
const vulns = data.vulnerabilities || [];
vulns.sort((a, b) => (b.dateAdded || '').localeCompare(a.dateAdded || ''));
return [{ json: { recent_kev: vulns.slice(0, 5) } }];

const output = (($input.first().json && $input.first().json.output) || '').toString();

const sentinel = '===JIRA===';
const descSentinel = '===JIRA-DESCRIPTION===';
const endSentinel = '===JIRA-END===';

const sentinelIdx = output.indexOf(sentinel);

if (sentinelIdx === -1) {
  // Defensive path: agent forgot the Jira block. Slack still works, Jira skipped.
  return [{ json: {
    slack_text: output,
    create_jira: false,
    jira_skip_reason: 'no ===JIRA=== sentinel found in agent output'
  }}];
}

const slack_text = output.slice(0, sentinelIdx).trimEnd();
const tail = output.slice(sentinelIdx + sentinel.length);

let metaStr = tail;
let description = '';

const descIdx = tail.indexOf(descSentinel);
if (descIdx >= 0) {
  metaStr = tail.slice(0, descIdx);
  const afterDesc = tail.slice(descIdx + descSentinel.length);
  const endIdx = afterDesc.indexOf(endSentinel);
  description = (endIdx >= 0 ? afterDesc.slice(0, endIdx) : afterDesc).trim();
}

let meta;
try {
  meta = JSON.parse(metaStr.trim());
} catch (e) {
  return [{ json: {
    slack_text,
    create_jira: false,
    jira_skip_reason: 'failed to parse Jira JSON: ' + e.message
  }}];
}

if (!meta || meta.create !== true) {
  return [{ json: {
    slack_text,
    create_jira: false,
    jira_skip_reason: (meta && meta.reason) || 'create flag not true'
  }}];
}

return [{ json: {
  slack_text,
  create_jira: true,
  jira_summary: meta.summary || '(no summary)',
  jira_priority: meta.priority || 'Medium',
  jira_labels: Array.isArray(meta.labels) ? meta.labels : [],
  jira_description_wiki: description || '(no description)'
}}];
